void Text_Holder.ScrollTextUp(int textID)

{

   if( textMode == 0 ) return;



   SetCursor(3);

}





void Text_Holder.ScrollTextDown(int textID)

{

   if( textMode == 0 ) return;



   SetCursor(4);

}





void Text_Holder.EndScrollText(int textID)

{

   if( textMode == 0 ) return;

   if(playStatus)  SetCursor(2);

   else            SetCursor(5);

}





void Text_Holder.MouseMoveIn(int textID)

{

   if( textMode == 0 ) return;



   if(playStatus)

      SetCursor(2);

   else

      SetCursor(5);

}





void Text_Holder.MouseMoveOut(int textID)

{

   SetCursor(0);

}





void Text_Holder.ClickOnText(int textID)

{

   if( textMode == 0 ) return;



   if(playStatus)

   {

      playStatus=0;

      Sound_Holder.Stop(3);

      Text_Holder.StopSynchroText(0);

      Sound_Holder.SetPlayDSoundParameters( 2, 0, 0, 0 );

      SetCursor(5);

   }

   else

   {

      playStatus=1;

      Sound_Holder.SetPlayDSoundParameters( 2, -1000, 0, 0 );

      Text_Holder.PlaySynchroText(0);

      SetCursor(2);

   }

}





void Text_Holder.EndOfSynchroText(int textID)

{

   if(playStatus)

      SetCursor(5);

   else

      SetCursor(0);

   playStatus=0;

   Sound_Holder.SetPlayDSoundParameters( 2, 0, 0, 0 );

}





void Sound_Holder.EndPlaySound(int soundID)

{

   if(soundID==3 && textMode)

   { 

      playStatus=1;

      Text_Holder.EnableMouse(0);

      Text_Holder.PlaySynchroText(0);

      return;

   }

   if(soundID==10)    return;

   if(soundID==18 || soundID==19)

   {

      fraza=-1;

      canPlay=1;

      return;

   }

   if(soundID==11)

   {

      Bitmap_Holder.ShowBitmap(8);

      if(tamClick)   

      {

Debug("1");

         error=fraza;



//         while(fraza==error)   fraza=Random(0,5);



         fraza=frazaCount;



         tamClick=0;

      }

Debug("2");

      Sound_Holder.PlayDSound(12+fraza);

      error=0;

      step=0;

      canPlay=0;

      return;

   }

   if(soundID>11)

   {

      canPlay=1;

      Bitmap_Holder.HideBitmap(8);

      SetTimer(20000);

   }

}



void HotSpot_Holder.LeftButtonClickOnUp(int rectID)

{

   if(rectID>6)   Bitmap_Holder.HideBitmap(rectID-5);

}





void Sprite_Holder.EndAnimation(int spriteID)

{

   Sprite_Holder.ChangePhase(spriteID,0);

   Sprite_Holder.HideSprite(spriteID);

}





void OnLButtonDown(int x,int y)

{

        //Add your command handler code here

   helpTime=-1;

   Sound_Holder.Stop(20);

}



void OnRButtonDown(int x,int y)

{

        //Add your command handler code here

   Sound_Holder.PlayDSound(20);

   helpTime=-1;

}
